module thresholding (  
    input [7:0] pixel_value,  
    input [2:0] threshold,  
    output reg result  
);  
  wire [7:0] _tap_pixel_value = pixel_value & {8{1'b1}};

    always @(*) begin  
        if (pixel_value >= threshold)  
            result = 1;  
        else  
            result = 0;  
    end  
endmodule
